// Demo configuration. Keep secrets in environment variables or n8n credentials.
return [{ json: {
  openai:   { model: 'gpt-4o-mini' },
  launchApi:{ base: 'https://ll.thespacedevs.com/2.2.0' },
  callmebot:{ enabled: true },
  discord:  { enabled: false, webhookUrl: 'https://discord.com/api/webhooks/XXX/YYY' },
  forceMode:'auto',        // 'auto' | 'preview' | 'recap'  (force a branch for demos)
  recapWindowHours: 24
}}];

const cfg  = $('Config').first().json;
const up   = ($('Get Upcoming Launch').first().json.results || [])[0] || null;
const prevResults = $('Get Previous Launch').first().json.results || [];
const prev = prevResults[0] || null;
function shape(l){
  if(!l) return null;
  let webcast = '';
  if (Array.isArray(l.vidURLs) && l.vidURLs[0]) webcast = l.vidURLs[0].url || '';
  return {
    id: l.id, name: l.name,
    status: (l.status && l.status.name) || 'Unknown',
    net: l.net,
    provider: (l.launch_service_provider && l.launch_service_provider.name) || '',
    rocket: (l.rocket && l.rocket.configuration && (l.rocket.configuration.full_name || l.rocket.configuration.name)) || '',
    mission: (l.mission && l.mission.name) || '',
    mission_description: (l.mission && l.mission.description) || '',
    pad: (l.pad && l.pad.name) || '',
    location: (l.pad && l.pad.location && l.pad.location.name) || '',
    image: l.image || '', webcast
  };
}
let mode = cfg.forceMode;
if(!mode || mode === 'auto') {
  mode = 'preview';
  if(prev && prev.net){
    const ageH = (Date.now() - new Date(prev.net).getTime()) / 3600000;
    if(ageH >= 0 && ageH <= (cfg.recapWindowHours || 24)) mode = 'recap';
  }
}
const previousLaunches = prevResults.map(shape).filter(Boolean);
const launch = (mode === 'recap' ? shape(prev) : shape(up)) || {
  name:'To be announced', status:'TBD', net:null, provider:'', rocket:'',
  mission:'', mission_description:'', pad:'', location:'', image:'', webcast:''
};
const aiUser = [
  'Name: '    + launch.name,
  'Status: '  + launch.status,
  'Provider: '+ launch.provider,
  'Rocket: '  + launch.rocket,
  'Mission: ' + launch.mission,
  'Pad: '     + launch.pad + ' (' + launch.location + ')',
  'NET: '     + (launch.net || 'TBD'),
  'Details: ' + (launch.mission_description || '').slice(0, 700)
].join(String.fromCharCode(10));
return [{ json: { mode, launch, previousLaunches, aiUser, generatedAt: new Date().toISOString() } }];

