const sd  = $getWorkflowStaticData('global');
const sel = $('Select Headline').first().json;
const ai  = ($json.choices && $json.choices[0] && $json.choices[0].message
            && $json.choices[0].message.content) || '';
const launch = sel.launch || {};

// Persist latest state for the webhook page.
sd.latest = {
  mode: sel.mode,
  launch,
  previousLaunches: Array.isArray(sel.previousLaunches) ? sel.previousLaunches : [],
  briefing: ai.trim(),
  generatedAt: new Date().toISOString()
};
if(!Array.isArray(sd.notifications)) sd.notifications = [];

const cfg = $('Config').first().json;
const verb = sel.mode === 'recap' ? 'RECAP' : 'PREVIEW';
const nl = String.fromCharCode(10);
const message = '🚀 ' + verb + ': ' + (launch.name || 'TBD') + nl
  + (launch.provider || '') + ' • ' + (launch.rocket || '') + nl
  + 'NET ' + (launch.net || 'TBD') + nl + nl + sd.latest.briefing;

return [{ json: {
  message, mode: sel.mode, launchName: launch.name || 'TBD',
  whatsapp: cfg.callmebot, discord: cfg.discord
}}];

const sd = $getWorkflowStaticData('global');
if(!Array.isArray(sd.notifications)) sd.notifications = [];
const bn = $('Build Notification').first().json;
sd.notifications.unshift({
  channel: 'WhatsApp',
  target: 'env:CALLMEBOT_PHONE',
  title: bn.launchName,
  status: 'dispatched',
  at: new Date().toISOString()
});
sd.notifications = sd.notifications.slice(0, 25);
return [{ json: { logged: true } }];

const sd = $getWorkflowStaticData('global');
if(!Array.isArray(sd.notifications)) sd.notifications = [];
const bn = $('Build Notification').first().json;
