  target: 'discord-webhook',
  title: bn.launchName,
  status: 'dispatched',
  at: new Date().toISOString()
});
sd.notifications = sd.notifications.slice(0, 25);
return [{ json: { logged: true } }];

const sd = $getWorkflowStaticData('global');
return [{ json: {
  hasData: !!sd.latest,
  latest: sd.latest || null,
  notifications: Array.isArray(sd.notifications) ? sd.notifications : []
}}];

