<script>/*BOOT*/</script>
<script>
(function(){
  "use strict";

  // ===== CONFIG =================================================
  // Leave empty when this page is SERVED BY n8n (same origin).
  // For GitHub Pages / standalone hosting, set this to your full
  // n8n webhook URL, e.g. "https://your-n8n.example.com/webhook/launch-board".
  var API_URL = "";
  // =============================================================

  function jsonUrl(){
    var base = API_URL || (location.origin + location.pathname);
    var sep = base.indexOf("?") > -1 ? "&" : "?";
    return base + sep + "format=json&_=" + Date.now();
  }

  var state = (window.__BOOT__ || {hasData:false, latest:null, notifications:[]});
  var selectedHistoryIndex = -1;

  function pad(n){ return ("0" + n).slice(-2); }
  function esc(s){ var d=document.createElement("div"); d.textContent=(s==null?"":String(s)); return d.innerHTML; }

  function fmtNet(iso){
    if(!iso) return "TBD";
    var d=new Date(iso);
    if(isNaN(d.getTime())) return "TBD";
    return d.toUTCString().replace("GMT","UTC");
  }

  function renderShell(){
    var root=document.getElementById("root");
    if(!state.hasData || !state.latest){
      root.innerHTML='<div class="card"><div class="empty">'+
        '<b style="color:#eaf1ff">Awaiting first telemetry sync.</b><br>'+
        'Trigger the schedule workflow in n8n (or wait for the next interval). '+
        'Once it runs, the next launch, an AI briefing, and the alert feed appear here.'+
        '</div></div>';
      document.getElementById("modeChip").textContent="STANDBY";
      return;
    }
    var history = Array.isArray(state.latest.previousLaunches) ? state.latest.previousLaunches : [];
    var L=(selectedHistoryIndex >= 0 && history[selectedHistoryIndex]) ? history[selectedHistoryIndex] : (state.latest.launch||{});
    var mode=(selectedHistoryIndex >= 0 ? "history" : (state.latest.mode||"preview")).toUpperCase();
    var brief=(selectedHistoryIndex >= 0 ? (L.mission_description || "Select another launch or run the workflow to refresh the latest briefing.") : (state.latest.briefing||""));
    var media=L.image ? 'style="background-image:url(\''+esc(L.image)+'\')"' : "";

    document.getElementById("modeChip").textContent=mode;
    var sc=document.getElementById("statusChip");
    if(L.status){ sc.style.display=""; sc.textContent=L.status;
      sc.style.background = /go|success|good/i.test(L.status) ? "#19d27c" : "#f0b53b"; }
    document.getElementById("syncLbl").textContent =
      "synced " + fmtNet(state.latest.generatedAt);

    root.innerHTML =
      '<div class="hero">'+
        '<div class="card">'+
          '<div class="media" '+media+'><div class="pad">'+esc(L.pad||"")+
            (L.location? " &middot; "+esc(L.location):"")+'</div></div>'+
          '<div class="body">'+
            '<h1 class="lname">'+esc(L.name||"To be announced")+'</h1>'+
            '<div class="lsub">'+esc(L.provider||"")+(L.rocket?" &middot; "+esc(L.rocket):"")+'</div>'+
            '<div class="grid2">'+
              cell("Mission", L.mission||"--")+
              cell("Vehicle", L.rocket||"--")+
              cell("Window (NET)", fmtNet(L.net))+
              cell("Status", L.status||"--")+
            '</div>'+
          '</div>'+
        '</div>'+
        '<div class="card clockwrap">'+
          '<div class="tlabel" id="tlabel">T-MINUS</div>'+
          '<div class="clock" id="clock"><span class="sgn">T-</span><span>--</span></div>'+
          '<div class="scan"></div>'+
        '</div>'+
      '</div>'+
      '<div class="cols">'+
        '<div class="card">'+
          '<div class="ph"><h2>AI Mission Briefing</h2><span class="src">gpt model &middot; live</span></div>'+
          '<div class="briefing">'+ (brief? esc(brief) : "Generating briefing on next sync...") +'</div>'+
        '</div>'+
        '<div class="card">'+
          '<div class="ph"><h2>Alert Feed</h2><span class="src">multi-channel</span></div>'+
          '<div class="feed" id="feed"></div>'+
        '</div>'+
      '</div>'+
      '<div class="cols">'+
        '<div class="card">'+
          '<div class="ph"><h2>Previous Launches</h2><span class="src">latest 10</span></div>'+
          '<div class="history" id="history"></div>'+
        '</div>'+
        '<div class="card">'+
          '<div class="ph"><h2>Selected Launch</h2><span class="src">click history item</span></div>'+
          '<div class="briefing" id="selectedDetails"></div>'+
        '</div>'+
      '</div>';
    renderFeed();
    renderHistory(history, L);
    tick();
  }

  function cell(k,v){
    return '<div><div class="k">'+esc(k)+'</div><div class="v">'+esc(v)+'</div></div>';
  }

  function renderHistory(history, selected){
    var wrap=document.getElementById("history"), details=document.getElementById("selectedDetails");
    if(!wrap || !details) return;
    if(!history.length){
      wrap.innerHTML='<div class="empty">Run the workflow once from Schedule Trigger to load previous launches.</div>';
      details.innerHTML='No previous-launch history loaded yet.';
      return;
    }
    var html="";
    for(var i=0;i<history.length;i++){
      var l=history[i]||{};
      var cls=(i===selectedHistoryIndex)?"hitem active":"hitem";
      html+='<button class="'+cls+'" data-history-index="'+i+'"><b>'+esc(l.name||"Unknown launch")+'</b>'+
        '<span>'+fmtNet(l.net)+' &middot; '+esc(l.provider||"")+' &middot; '+esc(l.status||"")+'</span></button>';
    }
    wrap.innerHTML=html;
    details.innerHTML='<b style="color:#eaf1ff">'+esc(selected.name||"Current launch")+'</b><br>'+
      esc(selected.provider||"")+(selected.rocket?' &middot; '+esc(selected.rocket):'')+'<br>'+
      esc(selected.pad||"")+(selected.location?' &middot; '+esc(selected.location):'')+'<br><br>'+
      esc(selected.mission_description||"No mission description available.");
    var buttons=wrap.querySelectorAll("[data-history-index]");
    for(var j=0;j<buttons.length;j++){
      buttons[j].addEventListener("click",function(){
        selectedHistoryIndex=parseInt(this.getAttribute("data-history-index"),10);
        renderShell();
      });
    }
  }

  function renderFeed(){
    var feed=document.getElementById("feed");
    if(!feed) return;
    var n=state.notifications||[];
    if(!n.length){ feed.innerHTML='<div class="empty">No alerts dispatched yet.</div>'; return; }
    var html="";
    for(var i=0;i<n.length;i++){
      var it=n[i];
      var ch=esc(it.channel||"Alert");
      html+='<div class="nrow">'+
        '<span class="nchip '+ch+'">'+ch+'</span>'+
        '<div class="ninfo"><b>'+esc(it.title||"Launch update")+'</b>'+
        '<span>'+esc(it.status||"sent")+' &middot; '+fmtNet(it.at)+'</span></div></div>';
    }
    feed.innerHTML=html;
  }

  function tick(){
    var el=document.getElementById("clock");
    if(!el || !state.latest || !state.latest.launch) return;
    var net=state.latest.launch.net;
    if(!net){ el.innerHTML='<span class="sgn">T-</span><span>TBD</span>'; return; }
    var diff=new Date(net).getTime()-Date.now();
    var past=diff<0; var s=Math.abs(Math.floor(diff/1000));
    var d=Math.floor(s/86400); s-=d*86400;
    var h=Math.floor(s/3600); s-=h*3600;
    var m=Math.floor(s/60); s-=m*60;
    document.getElementById("tlabel").textContent = past ? "T-PLUS (LIFTOFF)" : "T-MINUS";
    el.className = "clock" + (past? " go":"");
    el.innerHTML='<span class="sgn">'+(past?"T+":"T-")+'</span>'+
      seg(d,"DAYS")+seg(pad(h),"HRS")+seg(pad(m),"MIN")+seg(pad(s),"SEC");
  }
  function seg(val,lbl){ return '<span class="seg"><span>'+val+'</span><u>'+lbl+'</u></span>'; }

  function fetchData(){
    fetch(jsonUrl(),{cache:"no-store"})
      .then(function(r){return r.json();})
      .then(function(d){ if(d){ state=d; if(selectedHistoryIndex >= ((state.latest&&state.latest.previousLaunches)||[]).length) selectedHistoryIndex=-1; renderShell(); } })
      .catch(function(){ /* keep last good render */ });
  }

